css:
.loader {
  width: fit-content;
  font-size: 34px;
  font-family: monospace;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #0f766e);
  background: linear-gradient(90deg,#0000 33%,var(--loader-color, #0f766e) 0 67%,#0000 0) 100%/300% 100% no-repeat text;
  animation: l12 4s steps(14) infinite;
}
.loader:before {
  content: "Loading";
}
@keyframes l12 {
  to {background-position: 0}
}
